async (params, browser) => {
  // Open LinkedIn post
  await browser.open(`${params.post_url}`)

  // Wait for post to load
  await browser.waitForSelector('div.feed-shared-update-v2, .feed-shared-update-v2__content', 15000)

  // Let post settle
  await browser.wait(2000)

  // Click comment button
  const open_comment = await browser.evaluate(`const commentBtn = document.querySelector('button[aria-label*="Comment"], button[aria-label*="comment"], button.comment-button, .social-actions-button[aria-label*="Comment"]'); if (commentBtn) { commentBtn.click(); return { clicked: true }; } return { clicked: false, message: 'Comment button not found' }`)

  await browser.wait(1500)

  // Wait for comment input
  await browser.waitForSelector('.ql-editor[data-placeholder], div.comments-comment-texteditor .ql-editor, div[contenteditable=\'true\'][data-placeholder*=\'comment\' i], div[contenteditable=\'true\'][data-placeholder*=\'Add\' i], .ql-editor[contenteditable=\'true\']', 10000)

  // Type comment
  const type_comment = await browser.evaluate(`const editor = document.querySelector('.ql-editor[data-placeholder], div.comments-comment-texteditor .ql-editor, div[contenteditable="true"][data-placeholder*="comment" i], div[contenteditable="true"][data-placeholder*="Add" i], .ql-editor[contenteditable="true"]'); if (!editor) throw new Error('Comment editor not found'); editor.focus(); editor.innerHTML = ''; const p = document.createElement('p'); p.textContent = params.comment; editor.appendChild(p); editor.dispatchEvent(new Event('input', { bubbles: true })); editor.dispatchEvent(new Event('change', { bubbles: true })); return { typed: true }`)

  await browser.wait(1000)

  // Submit comment
  const result = await browser.evaluate(`const submitBtn = document.querySelector('button.comments-comment-box__submit-button, button[aria-label*="Post comment"], button[data-control-name="comment_submit"], form.comments-comment-box button[type="submit"], button.comments-comment-box__submit-button--cr'); if (submitBtn && !submitBtn.disabled) { submitBtn.click(); return { success: true, message: 'Comment posted successfully' }; } const allBtns = document.querySelectorAll('button'); for (const btn of allBtns) { const text = btn.textContent.trim().toLowerCase(); const label = (btn.getAttribute('aria-label') || '').toLowerCase(); if ((text === 'post' || text === 'submit' || label.includes('post comment') || label.includes('submit')) && btn.closest('.comments-comment-box, .comments-comment-texteditor')) { btn.click(); return { success: true, message: 'Comment posted via fallback' }; } } return { success: false, message: 'Submit button not found or disabled - comment may not have been typed correctly' }`)

  return result
}
